import Vision
import UIKit

struct DetectedCode: Identifiable, Hashable {
    let id = UUID()
    let rawValue: String
    let symbology: VNBarcodeSymbology
    let confidence: VNConfidence
    let boundingBox: CGRect

    var normalized: NormalizedCode {
        BarcodeNormalizer.normalize(raw: rawValue, symbology: symbology)
    }
}

enum VisionBarcodeDetector {
    static func detect(in image: UIImage) async -> [DetectedCode] {
        guard let cg = image.cgImage else { return [] }

        return await withCheckedContinuation { cont in
            let request = VNDetectBarcodesRequest { req, _ in
                let results = (req.results as? [VNBarcodeObservation]) ?? []
                let codes: [DetectedCode] = results.compactMap { obs in
                    guard let raw = obs.payloadStringValue, !raw.isEmpty else { return nil }
                    return DetectedCode(
                        rawValue: raw,
                        symbology: obs.symbology,
                        confidence: obs.confidence,
                        boundingBox: obs.boundingBox
                    )
                }
                cont.resume(returning: codes)
            }
            request.symbologies = [.qr, .ean8, .ean13, .upce, .code39, .code128, .pdf417, .aztec, .dataMatrix]

            let handler = VNImageRequestHandler(cgImage: cg)
            DispatchQueue.global(qos: .userInitiated).async {
                try? handler.perform([request])
            }
        }
    }
}

canonicalCode.BarcodeNormalizer.swift:
import Foundation
import Vision

struct NormalizedCandidate: Hashable {
    let label: String
    let value: String
}

struct NormalizedCode: Hashable {
    /// The value you show prominently + copy by default.
    let displayValue: String
    /// The original payloadStringValue.
    let rawValue: String
    /// Optional hint shown near the primary value.
    let note: String?
    /// Optional labeled alternatives (e.g. UPS/FedEx/USPS candidates).
    let candidates: [NormalizedCandidate]
}

enum BarcodeNormalizer {
    static func normalize(raw: String, symbology: VNBarcodeSymbology) -> NormalizedCode {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return NormalizedCode(displayValue: "", rawValue: raw, note: nil, candidates: [])
        }

        let digitsOnly = trimmed.filter { $0.isNumber }
        let upperAlnum = trimmed.uppercased().filter { $0.isLetter || $0.isNumber }

        var candidates: [NormalizedCandidate] = []
        func add(_ label: String, _ value: String) {
            let v = value.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !v.isEmpty else { return }
            if candidates.contains(where: { $0.value == v }) { return }
            candidates.append(.init(label: label, value: v))
        }

        // UPS 1Z format (18 chars).
        if upperAlnum.hasPrefix("1Z"), upperAlnum.count >= 18 {
            add("UPS (1Z)", String(upperAlnum.prefix(18)))
        }

        if !digitsOnly.isEmpty {
            switch digitsOnly.count {
            case 12:
                add("FedEx (12 digits)", digitsOnly)
            case 15:
                add("FedEx (15 digits)", digitsOnly)
            case 20:
                add("Carrier (20 digits)", digitsOnly)
            case 22:
                add("USPS (22 digits)", digitsOnly)
            default:
                break
            }

            if digitsOnly.count > 22 {
                let last22 = String(digitsOnly.suffix(22))
                add("USPS candidate (last 22)", last22)

                // If the last 22 starts with 9, it's very likely a USPS tracking number.
                // Suppress shorter suffix candidates (they're usually just chopped versions) to reduce noise.
                if !last22.hasPrefix("9") {
                    add("Carrier candidate (last 20)", String(digitsOnly.suffix(20)))
                    add("FedEx candidate (last 15)", String(digitsOnly.suffix(15)))
                    add("FedEx candidate (last 12)", String(digitsOnly.suffix(12)))
                }
            }
        }

        if symbology == .qr {
            return NormalizedCode(displayValue: trimmed, rawValue: trimmed, note: nil, candidates: candidates)
        }

        if let primary = candidates.first {
            return NormalizedCode(displayValue: primary.value, rawValue: trimmed, note: primary.label, candidates: candidates)
        }

        return NormalizedCode(displayValue: trimmed, rawValue: trimmed, note: nil, candidates: [])
    }
}
